THE RISK:
{
 "id": "enefg-grid-slip-de-demand",
 "title": "EnEfG efficiency mandates plus 24–36-month Frankfurt grid queues push German new-build PDU orders past the YAM window while the snapshot TAM stays flat",
 "narrative": "PDU revenue recognizes at fit-out and energization — not at announcement. Germany's Energy Efficiency Act (EnEfG) imposes PUE ≤1.2 and waste-heat-reuse duties on data centres commencing operation from mid-2026, forcing design rework on exactly the pipeline the entrant would sell into; simultaneously Frankfurt grid connections face documented 24–36-month waits and FLAP-D prices are rising. The market data that looks like strength — record-low 6.3% vacancy, 83% pre-let pipeline — actually means replacement demand cannot compensate for slipped new-build fit-outs inside 12 months. geo.DE's 0.50 is a 2025 capacity snapshot; the Year-1 orderable German slice is smaller and slower than the funnel implies, and Germany is half the funnel.",
 "category": "exogenous",
 "targetNodes": [
  "geo.DE",
  "obtainableFactor"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "EnEfG PUE/waste-heat mandates bite for German DCs commencing operation from mid-2026 (with EED 2024/1791 layering KPI disclosure), while Frankfurt — ~60–75% of German capacity — faces 24–36-month grid-connection waits and 12% FLAP-D price rises in 2026",
   "refs": [
    "digest:serviceable-benchmark#c9",
    "digest:geo-DE#c20",
    "digest:geo-DE#c1"
   ]
  },
  {
   "step": "propagation",
   "text": "New-build fit-outs — the moment rack PDUs are specified and ordered — slip as designs are reworked for compliance and energization dates move right; with vacancy at a record-low 6.3% and the pipeline 83% pre-let, there is no slack inventory of halls generating near-term replacement PDU demand to offset the slip",
   "refs": [
    "digest:geo-DE#c21",
    "ledger:geo.DE"
   ]
  },
  {
   "step": "model-impact",
   "text": "The German half of the funnel is a static 2025 snapshot: the Year-1 orderable DE slice is smaller in absolute terms and converts slower than geo.DE 0.50 × obtainableFactor 0.03 implies — a timing hollow-out invisible in the level-based bands",
   "refs": [
    "ledger:geo.DE",
    "ledger:obtainableFactor"
   ]
  }
 ],
 "whyMissable": "Every headline the founder reads — record-low vacancy, pre-let pipelines, AI demand — files under upside. The list logs 'booming German market' as a strength and never inverts it: PDU revenue lands at fit-out/energization, which is precisely the step that regulation and grid queues delay.",
 "expectedObviousness": "medium",
 "falsifier": "2026 quarterly Frankfurt/Berlin market reports (JLL/CBRE) showing white-space fit-outs and energizations proceeding on original schedules despite EnEfG requirements and grid constraints, with under-construction MW converting to live MW at historical rates.",
 "likelihood": {
  "value": 0.4,
  "rationale": "Grid waits of 24–36 months and EnEfG dates are documented; JLL data already shows a large gap between live (745 MW) and under-construction/planned Frankfurt capacity. The uncertainty is the magnitude of Year-1 order slippage, not its existence. [evidence revision: All three mechanism triggers are independently and precisely corroborated (statutory PUE ≤1.2 text, documented 24–36-month grid waits, record-low vacancy with no replacement slack), which strengthens the causal chain modestly beyond the prior 0.35. The upward revision is bounded because (a) a pending EnEfG novelle could delay/soften the mandate, weakening the design-rework trigger, (b) the CBRE/JLL falsifier data is not conclusively resolved — several Frankfurt facilities are still completing, and (c) the load-bearing model-impact claim (Year-1 orderable slice smaller/slower than geo.DE 0.50 implies) remains an inference rather than directly observed slippage.]",
  "basis": "evidence",
  "revisedFrom": 0.35
 },
 "perturbation": [
  {
   "nodeId": "geo.DE",
   "op": "set",
   "value": 0.45,
   "note": "Year-1 orderable DE slice smaller in absolute terms as new-build fit-outs slip past the window — deliberate non-renormalization: absolute shrink, not mix shift"
  },
  {
   "nodeId": "obtainableFactor",
   "op": "scale",
   "value": 0.8,
   "note": "conversion pace slows as pipeline orders defer to energization dates"
  }
 ],
 "indicators": [
  {
   "signal": "Announced energization/commissioning slips at flagship German builds",
   "where": "JLL German data-center quarterly reports; TenneT/Amprion grid-connection announcements; operator capex calls (e.g., Vantage, NTT GDC Europe)",
   "threshold": "≥2 flagship Frankfurt/Berlin builds announcing 6+ month slips to energization",
   "updates": "increases"
  },
  {
   "signal": "EnEfG enforcement and transition-waiver practice for data centres",
   "where": "BfEE/BAFA guidance dockets; German Datacenter Association (germandatacenters.com) position papers",
   "threshold": "strict application of PUE/heat-reuse rules to 2026 commencements without transitional waivers",
   "updates": "increases"
  }
 ],
 "mitigations": [
  {
   "action": "Survey order-timing across the 2026 German fit-out pipeline (when are PDUs specified vs energized) to date the DE revenue window directly",
   "type": "information",
   "voiNodeId": "geo.DE",
   "note": "converts the snapshot 0.50 into a dated orderable share"
  },
  {
   "action": "Weight the Year-1 pipeline toward NL and PL, where efficiency mandates are lighter and capacity growth is faster",
   "type": "strategic",
   "voiNodeId": null,
   "note": null
  },
  {
   "action": "Build a retrofit/refresh offer for operating halls (monitoring upgrades in live capacity) that is insensitive to new-build energization slips",
   "type": "operational",
   "voiNodeId": null,
   "note": null
  }
 ],
 "evidenceStatus": "corroborated",
 "evidence": [
  {
   "title": "§ 11 EnEfG Klimaneutrale Rechenzentren",
   "sourceType": "industry-report",
   "publisher": "Bundesministerium der Justiz (gesetze-im-internet.de)",
   "date": null,
   "excerpt": "Rechenzentren, die ab dem 1. Juli 2026 den Betrieb aufnehmen, sind so zu errichten und zu betreiben, dass sie eine Energieverbrauchseffektivität von kleiner oder gleich 1,2 erreichen und einen Anteil an wiederverwendeter Energie ... von mindestens 10 Prozent aufweisen",
   "url": "https://www.gesetze-im-internet.de/enefg/__11.html",
   "attached": true
  },
  {
   "title": "Data Centres in 2026: Power Becomes the Decisive Asset-Class Question",
   "sourceType": "analyst-estimate",
   "publisher": "neospaces",
   "date": "2026-05-31",
   "excerpt": "Frankfurt carries around 745 MW of IT load, yet grid connections face 24-to-36-month waits and FLAP-D prices rise 12 percent in 2026. Whoever secures power capacity will control the market.",
   "url": "https://neospaces.de/en/insights/germany-data-center-market-2026-05-31",
   "attached": true
  },
  {
   "title": "EMEA year end data centre report 2025",
   "sourceType": "industry-report",
   "publisher": "JLL",
   "date": "2026-03-30",
   "excerpt": "FLAP-D vacancy hits record low of 6.3%, pipeline is 83% pre-let. Capacity is being absorbed faster than it can be replaced. Pre-commitment is now the only viable route to securing meaningful capacity.",
   "url": "https://www.jll.com/en-uk/insights/emea-data-centre-report",
   "attached": true
  }
 ],
 "stances": [
  {
   "url": "https://www.gesetze-im-internet.de/enefg/__11.html",
   "stance": "supports",
   "quote": "Rechenzentren, die ab dem 1. Juli 2026 den Betrieb aufnehmen, sind so zu errichten und zu betreiben, dass sie 1.\n\neine Energieverbrauchseffektivität von kleiner oder gleich 1,2 erreichen und\n\n2.\n\neinen Anteil an wiederverwendeter Energie nach DIN EN 50600-4-6, Ausgabe November 20207 von mindestens 10 Prozent aufweisen"
  },
  {
   "url": "https://www.anwalt.de/rechtstipps/enefg-fuer-rechenzentren-welche-pflichten-jetzt-gelten-und-was-die-novelle-2026-daran-aendert-273697.html",
   "stance": "contradicts",
   "quote": "eine Novelle, die in der Ressortabstimmung weit fortgeschritten ist, würde diese Anforderungen wieder verschieben. Wer plant oder in Betrieb nimmt, muss beide Rechtsstände kennen."
  },
  {
   "url": "https://neospaces.de/en/insights/germany-data-center-market-2026-05-31",
   "stance": "supports",
   "quote": "Frankfurt carries around 745 MW of IT load, yet grid connections face 24-to-36-month waits and FLAP-D prices rise 12 percent in 2026"
  },
  {
   "url": "https://www.jll.com/en-uk/insights/emea-data-centre-report",
   "stance": "supports",
   "quote": "FLAP-D vacancy hits record low of 6.3%, pipeline is 83% pre-let. Capacity is being absorbed faster than it can be replaced. Pre-commitment is now the only viable route to securing meaningful capacity across Europe."
  },
  {
   "url": "https://www.igorslab.de/en/frankfurt-at-its-limit-power-shortages-are-slowing-the-boom-in-data-centers/",
   "stance": "supports",
   "quote": "The energy provider Mainova estimates that high-capacity new connections on a large scale will not be possible again until the mid-2030s."
  },
  {
   "url": "https://www.datacenterdynamics.com/en/news/cyrusone-completes-shell-and-core-of-fra5-in-frankfurt-germany/",
   "stance": "contradicts",
   "quote": "The first 9MW phase of capacity was due to be delivered in Q3 2024. CyrusOne has not provided updated timelines."
  }
 ]
}

